Object -> {
  String:id
  bool:marked -> false
  List{T <- Object}:refs -> {}
}

Heap -> {
  List{T <- Object}:objects
  List{T <- Object}:roots
}

Mark -> { Object:obj }
Sweep -> {}

gc -> {
  Heap:h
  Mark -< e {
    -> Object{marked -> true}
  }
  Sweep -< e {
    -> h.objects
  }
  run -> {
    >- Mark{obj -> h.roots}
    >- Sweep{}
  }
}
